// Host is the resolver for the host field.
func (r *queryResolver) Host(ctx context.Context) (*graphql1.Host, error) {
	var h *graphql1.Host
	if r.HostProvider != nil {
		got, _, err := r.HostProvider.Get(ctx, r.HostProvider.LocalID())
		if err != nil {
			return nil, fmt.Errorf("host: %w", err)
		}
		h = got
	} else if r.PS != nil {
		h = &graphql1.Host{ID: r.PS.HostID()}
	} else if r.HostServiceProvider != nil {
		hostID := r.HostServiceProvider.HostID()
		h = &graphql1.Host{ID: "Host:" + hostID, MachineID: hostID}
	} else {
		return nil, fmt.Errorf("host provider not initialised")
	}
	if r.HostServiceProvider != nil {
		machineID := r.HostServiceProvider.HostID()
		h.HostServices = buildHostServices(ctx, r.HostServiceProvider, machineID)
	}
	return h, nil
}

// Hosts is the resolver for the hosts field.
//
// Returns the live-fleet view: local host + federated peers. The local
// host's purpose is enriched from the peer config when set.
func (r *queryResolver) Hosts(ctx context.Context) ([]*graphql1.Host, error) {
	local, err := r.Query().Host(ctx)
	if err != nil {
		return nil, err
	}
	hosts := []*graphql1.Host{local}
	if r.PeerProxy != nil {
		hostRes := r.Resolver.Host()
		peers, err := hostRes.Peers(ctx, local)
		if err != nil {
			return nil, err
		}
		hosts = append(hosts, peers...)
		if p := purposeForLocalHost(local, r.PeerProxy.Peers()); p != "" {
			local.Purpose = &p
		}
	}
	return hosts, nil
}

// Repos is the resolver for the repos field.
func (r *queryResolver) Repos(ctx context.Context) ([]*graphql1.Repo, error) {
	if r.ReposProvider == nil {
		return nil, fmt.Errorf("repos provider not wired: daemon misconfigured")
	}
	rows, err := r.ReposProvider.List(ctx)
	if err != nil {
		return nil, fmt.Errorf("list repos: %w", err)
	}
	out := make([]*graphql1.Repo, 0, len(rows))
	for _, row := range rows {
		out = append(out, &graphql1.Repo{
			ID:   string(row.ID),
			Slug: row.Slug,
			Path: row.Path,
		})
	}
	sort.Slice(out, func(i, j int) bool { return out[i].ID < out[j].ID })
	return out, nil
}

