// Process returns the OS-level Process for the pane's foreground pid (nil when the pid is missing or absent from the cached ps snapshot). cwd resolution is delegated to processResolver.Cwd and fires only when the client selects cwd. Host segment of the pane id is preserved on the projected Process node so future federated lookup attributes it to the correct peer host; today lookupPane only resolves local-tmux panes.
func (r *tmuxPaneResolver) Process(ctx context.Context, obj *graphql1.TmuxPane) (*graphql1.Process, error) {
	if r.PS == nil {
		return nil, nil
	}
	pane, ok := r.lookupPane(obj.ID)
	if !ok || pane.CurrentPid == 0 {
		return nil, nil
	}
	host, _, ok := splitTmuxPaneID(obj.ID)
	if !ok {
		return nil, nil
	}
	target := ps.ProcessID{Host: host, PID: pane.CurrentPid}
	got, _, err := r.PS.GetMany(ctx, []ps.ProcessID{target})
	if err != nil {
		return nil, nil
	}
	proc, ok := got[target]
	if !ok {
		return nil, nil
	}
	return projectProcess(&proc, host), nil
}

// ClaudeInstance resolves the ClaudeInstance running inside this pane.
// Pane-first path (ADR-022 Phase 5): builds the instance directly from the
// pane when the pane's command is "claude". Returns nil when Tmux is not
// wired or the pane is not a claude pane.
func (r *tmuxPaneResolver) ClaudeInstance(ctx context.Context, obj *graphql1.TmuxPane) (*graphql1.ClaudeInstance, error) {
	if r.Tmux == nil || obj == nil {
		return nil, nil
	}
	// obj is a thin handle: tmuxWindowResolver.Panes projects panes through
	// projectPane(), which sets {ID, PaneID} and nothing else. Every sibling
	// field resolver (currentCommand, currentPid, process) therefore looks the
	// pane up in the provider rather than reading obj. This one used to read
	// obj.CurrentCommand, which compared "" against "claude" and so returned
	// nil for EVERY pane, always — attend.js reads this field and treats null
	// as healthy, leaving the attention feed blind to every worker (#706).
	p, ok := r.lookupPane(obj.ID)
	if !ok {
		return nil, nil
	}
	host := string(r.Tmux.Host())
	// Only project panes running claude — same two-signal detection as
	// Query.claudeInstances, so both surfaces agree on what "running claude" means.
	if !tmux.PaneRunsCommand(p, host, newResolverPanePsGetter(r.PS), "claude") {
		return nil, nil
	}
	qr := &queryResolver{r.Resolver}
	// nil procTree: the single-pane path builds a one-off tree internally (#711).
	inst := qr.buildClaudeInstanceFromPane(ctx, projectPaneRich(p), host, nil, nil, nil, nil)
	return inst, nil
}

